// C2: Acting Components
instance LightingDimmerActuator : DTDFVocab:ActingComponent [
    base:desc "Lighting dimmer actuator defined in the enriched BIM model and addressable by the DT for actuation"
]

instance HVACControlValveActuator : DTDFVocab:ActingComponent [
    base:desc "HVAC control valve actuator defined in the enriched BIM model and addressable by the DT for actuation"
]

