    DTDFVocab:producedData TemperatureDataTransmitted
]

instance OccupancySensor : DTDFVocab:SensingComponent [
    base:desc "Occupancy sensor modeled in BIM; measurements ingested via Eclipse Hono"
    DTDFVocab:producedData OccupancyDataTransmitted
]

instance IlluminationSensor : DTDFVocab:SensingComponent [
    base:desc "Illumination sensor modeled in BIM; measurements ingested via Eclipse Hono"
    DTDFVocab:producedData IlluminationDataTransmitted
]

// C4: Physical-to-virtual interaction (DataTransmitted)
instance TemperatureDataTransmitted : DTDFVocab:DataTransmitted [
    DTDFVocab:producedFrom TemperatureSensor
]

instance OccupancyDataTransmitted : DTDFVocab:DataTransmitted [
    DTDFVocab:producedFrom OccupancySensor
]

instance IlluminationDataTransmitted : DTDFVocab:DataTransmitted [
    DTDFVocab:producedFrom IlluminationSensor
]

// C5: Data
instance TemperatureData : DTDFVocab:Data [
    base:desc "Live temperature measurements stream"
    DTDFVocab:fromData TemperatureDataTransmitted
    DTDFVocab:inputTo EclipseDittoTwinStore
]

instance OccupancyData : DTDFVocab:Data [
    base:desc "Live occupancy detection stream"
    DTDFVocab:fromData OccupancyDataTransmitted
    DTDFVocab:inputTo EclipseDittoTwinStore
]

instance IlluminationData : DTDFVocab:Data [
    base:desc "Live illumination level measurements stream"
    DTDFVocab:fromData IlluminationDataTransmitted
    DTDFVocab:inputTo EclipseDittoTwinStore
]

