]

instance DeviceMetadataModel : DTDFVocab:Model [
    base:desc "Metadata of devices generated from enriched BIM, used for automatic configurator generation"
    DTDFVocab:inputTo ModelDrivenEngineeringTool
]

instance ControlLogicModel : DTDFVocab:Model [
    base:desc "Control logic artifacts (e.g., HVAC set‑point rules) generated by the model‑driven pipeline"
